INSERT INTO storage.buckets (id, name, public) VALUES ('campaign-images', 'campaign-images', true) ON CONFLICT (id) DO NOTHING; CREATE POLICY "Authenticated users can upload campaign images" ON storage.objects FOR INSERT TO authenticated WITH CHECK (bucket_id = 'campaign-images'); CREATE POLICY "Public can view campaign images" ON storage.objects FOR SELECT TO public USING (bucket_id = 'campaign-images'); CREATE POLICY "Users can delete own campaign images" ON storage.objects FOR DELETE TO authenticated USING (bucket_id = 'campaign-images' AND (auth.uid()::text = (storage.foldername(name))[1] OR public.has_role(auth.uid(), 'admin'::app_role)));